import { useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useTranslation } from "react-i18next";
import { Ingredient, RecipeStep, RecipeDifficulty } from "@/components/community/recipe/RecipeTypes";

interface CreateRecipeParams {
  recipe_name: string;
  recipe_name_en?: string;
  recipe_name_pt?: string;
  subtitle?: string;
  subtitle_en?: string;
  subtitle_pt?: string;
  cook_time: number;
  difficulty: RecipeDifficulty;
  servings: number;
  ingredients: Ingredient[];
  steps: RecipeStep[];
  cover_image?: string | null;
  introduction?: string;
  introduction_en?: string;
  introduction_pt?: string;
  cooking_note?: string;
  // Optional fields
  nutrition?: {
    calories?: number;
    protein?: number;
    carbs?: number;
    fat?: number;
  };
  recipe_tags?: string[];
  recipe_category?: string;
  ai_recipe_source?: Record<string, any>;
  video_url?: string | null;
}

// Build structured content string: [[NOTE]]心得\n[[INTRO]]介绍
const buildContent = (note: string, intro: string) => {
  if (note && intro) return `[[NOTE]]${note}\n[[INTRO]]${intro}`;
  if (note) return `[[NOTE]]${note}`;
  return intro;
};

// Helper to translate text via edge function, returns original on failure
const translateText = async (text: string, targetLang: string): Promise<string> => {
  if (!text?.trim()) return "";
  try {
    const { data, error } = await supabase.functions.invoke("translate-content", {
      body: { text, targetLang },
    });
    if (error || !data?.translatedText) return text;
    return data.translatedText;
  } catch {
    return text;
  }
};

// Auto-translate missing multilingual fields
const autoTranslateFields = async (params: CreateRecipeParams) => {
  const source = params.recipe_name?.trim() || "";
  const subtitle = params.subtitle?.trim() || "";
  const intro = params.introduction?.trim() || "";

  // Use ALL ingredients/steps (not filtered) to maintain index alignment
  const ingredientNames = params.ingredients.map(i => i.name?.trim() || "—");
  const stepDescs = params.steps.map(s => s.description?.trim() || "—");

  // Build a combined translation block to minimize API calls
  const parts = [
    source || "—",
    subtitle || "—",
    intro || "—",
    ingredientNames.join("\n"),
    stepDescs.join("\n---STEP---\n"),
  ];
  const combined = parts.join("\n---FIELD---\n");

  // Determine which languages need translation
  const langsToTranslate: string[] = [];
  if (!params.recipe_name_en) langsToTranslate.push("en");
  if (!params.recipe_name_pt) langsToTranslate.push("pt");

  if (langsToTranslate.length === 0) return {};

  // Translate in parallel for each missing language
  const translations = await Promise.all(
    langsToTranslate.map(async (lang) => {
      const translated = await translateText(combined, lang);
      const fieldParts = translated.split("\n---FIELD---\n");
      const tName = fieldParts[0]?.trim() || source;
      const tSubtitle = (fieldParts[1]?.trim() === "—" ? "" : fieldParts[1]?.trim()) || "";
      const tIntro = (fieldParts[2]?.trim() === "—" ? "" : fieldParts[2]?.trim()) || "";
      const tIngredients = fieldParts[3]?.trim()
        ? fieldParts[3].trim().split("\n").map(s => s.trim() === "—" ? "" : s.trim())
        : ingredientNames;
      const tSteps = fieldParts[4]?.trim()
        ? fieldParts[4].trim().split("\n---STEP---\n").map(s => s.trim() === "—" ? "" : s.trim())
        : stepDescs;
      return { lang, name: tName, subtitle: tSubtitle, intro: tIntro, ingredients: tIngredients, steps: tSteps };
    })
  );

  const results: Record<string, { name: string; subtitle: string; intro: string; ingredients: string[]; steps: string[] }> = {};
  for (const t of translations) {
    results[t.lang] = t;
  }
  return results;
};

export const useCreateRecipe = () => {
  const queryClient = useQueryClient();
  const { t } = useTranslation();

  return useMutation({
    mutationFn: async (params: CreateRecipeParams) => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      // Auto-translate missing multilingual fields
      let translatedFields: Record<string, any> = {};
      try {
        translatedFields = await autoTranslateFields(params);
      } catch (err) {
        console.warn("Auto-translate failed, proceeding without translations:", err);
      }

      const enT = translatedFields["en"];
      const ptT = translatedFields["pt"];

      // Apply translations to ingredients
      const translatedIngredients = params.ingredients.map((ing, idx) => ({
        ...ing,
        name_en: ing.name_en || enT?.ingredients?.[idx] || ing.name,
        name_pt: ing.name_pt || ptT?.ingredients?.[idx] || ing.name,
      }));

      // Apply translations to steps
      const translatedSteps = params.steps.map((step, idx) => ({
        ...step,
        description_en: step.description_en || enT?.steps?.[idx] || step.description,
        description_pt: step.description_pt || ptT?.steps?.[idx] || step.description,
      }));

      const recipeName_en = params.recipe_name_en || enT?.name || params.recipe_name;
      const recipeName_pt = params.recipe_name_pt || ptT?.name || params.recipe_name;
      const subtitle_en = params.subtitle_en || enT?.subtitle || params.subtitle || "";
      const subtitle_pt = params.subtitle_pt || ptT?.subtitle || params.subtitle || "";
      const intro_en = params.introduction_en || enT?.intro || params.introduction || "";
      const intro_pt = params.introduction_pt || ptT?.intro || params.introduction || "";

      const note = params.cooking_note?.trim() || "";
      // Primary content (zh) = note + zh introduction
      const content = buildContent(note, params.introduction?.trim() || "");
      // Localized content variants (note stays as-is, intro is localized)
      const content_en = buildContent(note, intro_en);
      const content_pt = buildContent(note, intro_pt);

      // Prepare image_urls (cover image first if present)
      const imageUrls: string[] = [];
      if (params.cover_image) {
        imageUrls.push(params.cover_image);
      }
      // Add step images (support both image_urls array and legacy image_url)
      params.steps.forEach(step => {
        if (step.image_urls && step.image_urls.length > 0) {
          step.image_urls.forEach(url => imageUrls.push(url));
        } else if (step.image_url) {
          imageUrls.push(step.image_url);
        }
      });

      // Insert the recipe post
      const { data, error } = await supabase
        .from("community_posts")
        .insert({
          author_id: user.id,
          post_type: "recipe",
          content,
          content_zh: content || null,
          content_en: content_en || null,
          content_pt: content_pt || null,
          image_urls: imageUrls,
          recipe_name: params.recipe_name,
          recipe_name_en: recipeName_en || null,
          recipe_name_pt: recipeName_pt || null,
          subtitle: params.subtitle || null,
          subtitle_en: subtitle_en || null,
          subtitle_pt: subtitle_pt || null,
          cook_time: params.cook_time,
          difficulty: params.difficulty,
          servings: params.servings,
          ingredients: translatedIngredients as unknown as any,
          steps: translatedSteps as unknown as any,
          nutrition: params.nutrition ? (params.nutrition as unknown as any) : null,
          recipe_tags: params.recipe_tags || null,
          recipe_category: params.recipe_category || null,
          ai_recipe_source: params.ai_recipe_source ? (params.ai_recipe_source as unknown as any) : null,
          video_url: params.video_url || null,
          status: "pending",
          moderation_status: "pending",
        } as any)
        .select()
        .single();

      if (error) throw error;

      // Call moderation function
      try {
        await supabase.functions.invoke("moderate-post", {
          body: {
            post_id: data.id,
            content,
            user_id: user.id,
            image_urls: imageUrls,
          },
        });
      } catch (err) {
        console.error("Moderation call failed:", err);
      }

      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["community-posts"] });
      queryClient.invalidateQueries({ queryKey: ["has-posted-today"] });
      toast.success(t("recipe.publishSuccess", "食谱发布成功"));
    },
    onError: (error) => {
      console.error("Create recipe error:", error);
      toast.error(t("recipe.publishError", "发布失败"));
    },
  });
};
